import { describe, it, expect } from "vitest";
import { quote } from "./quote.js";

describe("quote premium", () => {
  it.todo("returns just the processing fee when there are no items");
  it.todo("computes premium for a single sword (base + processing fee)");
  it.todo("computes premium for a single amulet");
  it.todo("computes premium for a single staff");
  it.todo("computes premium for a single potion");
  it.todo("computes premium for a single rune component");
  it.todo("computes premium for a single moonstone component");
  it.todo("sums base premiums for multiple distinct main items");
  it.todo("applies the 3-alike-component bundle price for 3 runes");
  it.todo("applies the 3-alike-component bundle price for 3 moonstones");
  it.todo("prices 4 alike components as one bundle of 3 plus one single");
  it.todo("prices 6 alike components as two bundles of 3");
  it.todo("does NOT bundle 3 components of different kinds (rune + moonstone mix)");
  it.todo("adds a 50% surcharge for cursed items");
  it.todo("adds a 30% surcharge for highly enchanted items (enchantment >= 5)");
  it.todo("applies a 20% loyalty discount for long-standing customers (>= 2 years)");
  it.todo("applies a 10% first-insurance surcharge on the first quote");
  it.todo("applies a 15% multi-contract discount on contracts after the first");
  it.todo("rounds in the MHPCO's favor (rounds up)");
});

