const PROCESSING_FEE = 5;

const basePremiumFor = (type: string): number => {
  if (type === "sword") return 100;
  return 0;
};

export const quote = (input: QuoteInput): number => {
  let total = 0;
  for (const item of input.items) {
    total += basePremiumFor(item.type);
  }
  if (input.contractIndex === 0) {
    total = total * 1.1;
  }
  return Math.ceil(total) + PROCESSING_FEE;
};

