  let pct = 0;
  if (item.cursed) pct += CURSED_SURCHARGE_PCT;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) pct += HIGH_ENCHANTMENT_SURCHARGE_PCT;
